/**
 * decode-quality-otel.test.ts — flag gate + best-effort emit fallback.
 *
 * The emitter's OTLP path needs a live backend to verify end-to-end (see the
 * deliverable note: unverifiable without an OTLP collector). What we CAN assert
 * without a backend: the MESH_QUALITY_REPORT flag gate, the metric-name
 * contract (framework §3), and that emit()/shutdown() never throw when
 * telemetry is stubbed/absent (degrades to a console log).
 */

import { describe, expect, it, vi } from 'vitest';
import {
  DecodeQualityOtelEmitter,
  MESH_DECODE_METRICS,
  MESH_DECODE_SERVICE_NAME,
  meshQualityReportEnabled,
} from './decode-quality-otel';
import { DecodeQualityReporter } from './decode-quality-reporter';

describe('MESH_QUALITY_REPORT flag gate (default OFF)', () => {
  it('is off when unset or falsey', () => {
    expect(meshQualityReportEnabled({})).toBe(false);
    expect(meshQualityReportEnabled({ MESH_QUALITY_REPORT: '0' })).toBe(false);
    expect(meshQualityReportEnabled({ MESH_QUALITY_REPORT: 'false' })).toBe(false);
    expect(meshQualityReportEnabled({ MESH_QUALITY_REPORT: '' })).toBe(false);
  });
  it('is on for 1/true/on', () => {
    expect(meshQualityReportEnabled({ MESH_QUALITY_REPORT: '1' })).toBe(true);
    expect(meshQualityReportEnabled({ MESH_QUALITY_REPORT: 'true' })).toBe(true);
    expect(meshQualityReportEnabled({ MESH_QUALITY_REPORT: 'on' })).toBe(true);
  });
});

describe('the §3 metric-name contract', () => {
  it('emits the framework-doc names verbatim', () => {
    expect(MESH_DECODE_SERVICE_NAME).toBe('gnosis-openai-mesh');
    expect(MESH_DECODE_METRICS.tps).toBe('mesh.decode.tps');
    expect(MESH_DECODE_METRICS.gradeOrdinal).toBe('mesh.decode.grade_ordinal');
    expect(MESH_DECODE_METRICS.componentGbs).toBe('mesh.decode.component.gbs');
    expect(MESH_DECODE_METRICS.componentMs).toBe('mesh.decode.component.ms');
    expect(MESH_DECODE_METRICS.divergentTokens).toBe('mesh.decode.divergent_tokens');
    expect(MESH_DECODE_METRICS.gradeDip).toBe('mesh.decode.grade_dip');
    expect(MESH_DECODE_METRICS.gradeUp).toBe('mesh.decode.grade_up');
  });
});

describe('emit() best-effort (no OTLP backend)', () => {
  it('never throws; degrades to a console log when telemetry is unavailable', async () => {
    // No OTEL endpoint configured + gnosis stubs @a0n/telemetry → console path.
    const emitter = new DecodeQualityOtelEmitter({
      model: 'mistral-7b',
      revision: 'test-rev',
      env: {}, // no OTLP endpoint
    });
    const logSpy = vi.spyOn(console, 'log').mockImplementation(() => undefined);
    const r = new DecodeQualityReporter({
      windowSize: 4,
      establishAfterTokens: 4,
    });
    let snapshot = null as ReturnType<DecodeQualityReporter['record']>;
    for (let i = 0; i < 4; i++) snapshot = r.record(1000 / 13);
    expect(snapshot).not.toBeNull();
    let emitError: unknown = null;
    try {
      await emitter.emit(snapshot!);
      await emitter.shutdown();
    } catch (err) {
      emitError = err;
    }
    expect(emitError).toBeNull();
    logSpy.mockRestore();
  });
});
